#[derive(Debug)]
pub struct MappabilityRecord<'a> {
    pub tx_name: &'a str,
    pub gene_name: &'a str,
    tx_multiplicity: [usize; MAPPABILITY_COUNTS_LEN],
    gene_multiplicity: [usize; MAPPABILITY_COUNTS_LEN],
